import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import '../styles/register.css';
import { pushToast } from '../../utils/toastBridge'

export const Register = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    username: '',
    email: '',
    farmName: '',
    password: '',
    passwordConfirm: '',
  });
  const error = null;
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showPasswordConfirm, setShowPasswordConfirm] = useState(false);

  const { register } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const validateForm = () => {
    if (!formData.fullName || !formData.username || !formData.email || !formData.farmName || !formData.password || !formData.passwordConfirm) {
      pushToast({ title: 'Thất bại', message: 'Vui lÃ²ng Ä‘iá»n Ä‘áº§y Ä‘á»§ thÃ´ng tin', type: 'error' });
      return false;
    }

    if (formData.password.length < 6) {
      pushToast({ title: 'Thất bại', message: 'Máº­t kháº©u pháº£i cÃ³ Ã­t nháº¥t 6 kÃ½ tá»±', type: 'error' });
      return false;
    }

    if (formData.password !== formData.passwordConfirm) {
      pushToast({ title: 'Thất bại', message: 'Máº­t kháº©u khÃ´ng khá»›p', type: 'error' });
      return false;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      pushToast({ title: 'Thất bại', message: 'Email khÃ´ng há»£p lá»‡', type: 'error' });
      return false;
    }

    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    pushToast({ title: 'Thất bại', message: '', type: 'error' });
    setLoading(true);

    if (!validateForm()) {
      setLoading(false);
      return;
    }

    const result = await register(
      formData.fullName,
      formData.username,
      formData.email,
      formData.password,
      formData.passwordConfirm,
      formData.farmName
    );
    setLoading(false);

    if (result.success) {
      // Redirect Ä‘áº¿n dashboard dá»±a trÃªn role
      const role = result.user?.role;
      if (role === 'ADMIN') {
        navigate('/admin/dashboard');
      } else if (role === 'OWNER') {
        navigate('/owner/dashboard');
      } else if (role === 'MANAGER') {
        navigate('/manager/dashboard');
      } else if (role === 'WORKER') {
        navigate('/worker/dashboard');
      } else if (role === 'TECHNICIAN') {
        navigate('/technician/dashboard');
      } else if (role === 'ACCOUNTANT') {
        navigate('/accountant/dashboard');
      } else if (role === 'STOREKEEPER') {
        navigate('/storekeeper/dashboard');
      } else {
        navigate('/');
      }
    } else {
      pushToast({ title: 'Thất bại', message: result.message, type: 'error' });
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-layout">
        <div className="center-panel">
          <div className="form-card form-card--large form-card--register">
            <div className="auth-brand-mark">
              <div className="auth-brand-mark__icon">ðŸ¦</div>
            </div>
            <form onSubmit={handleSubmit} className="auth-form auth-form--register">
              <h2>ÄÄƒng kÃ½</h2>

              {error && <div className="alert alert-error">{error}</div>}

              <div className="register-fields-grid">
                <div className="form-group">
                  <label htmlFor="fullName">Há» vÃ  tÃªn</label>
                  <input
                    id="fullName"
                    type="text"
                    name="fullName"
                    className="auth-text-input"
                    placeholder="Nháº­p há» vÃ  tÃªn"
                    value={formData.fullName}
                    onChange={handleChange}
                    disabled={loading}
                    required
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="username">TÃªn Ä‘Äƒng nháº­p</label>
                  <input
                    id="username"
                    type="text"
                    name="username"
                    className="auth-text-input"
                    placeholder="Nháº­p tÃªn Ä‘Äƒng nháº­p"
                    value={formData.username}
                    onChange={handleChange}
                    disabled={loading}
                    required
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="email">Email</label>
                  <input
                    id="email"
                    type="email"
                    name="email"
                    className="auth-text-input"
                    placeholder="Nháº­p email"
                    value={formData.email}
                    onChange={handleChange}
                    disabled={loading}
                    required
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="farmName">TÃªn tráº¡i nuÃ´i</label>
                  <input
                    id="farmName"
                    type="text"
                    name="farmName"
                    className="auth-text-input"
                    placeholder="Nháº­p tÃªn tráº¡i nuÃ´i"
                    value={formData.farmName}
                    onChange={handleChange}
                    disabled={loading}
                    required
                  />
                </div>
              </div>

              <div className="register-password-grid">
                <div className="form-group">
                  <label htmlFor="password">Máº­t kháº©u</label>
                  <div className="password-input-wrapper">
                    <input
                      id="password"
                      type={showPassword ? 'text' : 'password'}
                      name="password"
                      placeholder="Nháº­p máº­t kháº©u (tá»‘i thiá»ƒu 6 kÃ½ tá»±)"
                      value={formData.password}
                      onChange={handleChange}
                      disabled={loading}
                      required
                    />
                    <button
                      type="button"
                      className="password-toggle"
                      onClick={() => setShowPassword(!showPassword)}
                      tabIndex="-1"
                    >
                      {showPassword ? 'ðŸ‘ï¸â€ðŸ—¨ï¸' : 'ðŸ‘ï¸'}
                    </button>
                  </div>
                </div>

                <div className="form-group">
                  <label htmlFor="passwordConfirm">XÃ¡c nháº­n máº­t kháº©u</label>
                  <div className="password-input-wrapper">
                    <input
                      id="passwordConfirm"
                      type={showPasswordConfirm ? 'text' : 'password'}
                      name="passwordConfirm"
                      placeholder="XÃ¡c nháº­n máº­t kháº©u"
                      value={formData.passwordConfirm}
                      onChange={handleChange}
                      disabled={loading}
                      required
                    />
                    <button
                      type="button"
                      className="password-toggle"
                      onClick={() => setShowPasswordConfirm(!showPasswordConfirm)}
                      tabIndex="-1"
                    >
                      {showPasswordConfirm ? 'ðŸ‘ï¸â€ðŸ—¨ï¸' : 'ðŸ‘ï¸'}
                    </button>
                  </div>
                </div>
              </div>

              <button type="submit" className="btn btn-primary btn-block" disabled={loading}>
                {loading ? 'ðŸ”„ Äang Ä‘Äƒng kÃ½...' : 'âœï¸ ÄÄƒng kÃ½'}
              </button>
            </form>

            <div className="auth-footer">
              <p>
                ÄÃ£ cÃ³ tÃ i khoáº£n?{' '}
                <Link to="/login" className="auth-link">
                  ÄÄƒng nháº­p ngay
                </Link>
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Register;
